def range_summary(nums):
    if not nums:
        return ''

    runs = []
    current, count = nums[0], 1
    for i in nums[1:]:
        if i == current + 1:
            count += 1
        else:
            if count > 1:
                runs.append(f'{current}-{current+count-1}')
            else:
                runs.append(str(current))
            count = 1
            current = i
    if count > 1:
        runs.append(f'{current}-{current+count-1}')
    return ', '.join(runs)
